// Show telescope reticles
core.setStelProperty("TelescopeControl.flagTelescopeReticles", true);

// Check if reticles are visible
var visible = core.getStelProperty("TelescopeControl.flagTelescopeReticles");
core.debug("Telescope reticles visible:", visible);

// Read current reticle color
var colorStr = core.getStelProperty("TelescopeControl.reticleColor");
core.debug("Reticle color:", colorStr);

// Set reticle color to red (Qt6 Stellarium)
var red = new Color(1.0, 0.0, 0.0);
TelescopeControl.setReticleColor(red.toVec3f());

// Set label color to cyan
var cyan = new Color(0.0, 0.8, 1.0);
TelescopeControl.setLabelColor(cyan.toVec3f());

// Set FOV circle color to orange
var orange = new Color(1.0, 0.6, 0.2);
TelescopeControl.setCircleColor(orange.toVec3f());

// Set reticle color to bright green
var green = new Color(0.2, 0.9, 0.2);
TelescopeControl.setReticleColor(green.toVec3f());

// Read via property (recommended)
var colorStr = core.getStelProperty("TelescopeControl.reticleColor");
core.debug("Reticle color:", colorStr);

// Increase label font size for better visibility
TelescopeControl.setFontSize(16);

// Reset to default
TelescopeControl.setFontSize(12);

// Select a star and point telescope #1 to it
core.selectObjectByName("Sirius");
TelescopeControl.slewTelescopeToSelectedObject(1);

// Disconnect all telescopes
TelescopeControl.stopAllTelescopes();
core.debug("All telescopes stopped");
